def n_queens_count(n):
    # n is guaranteed to be in [1..8]
    count = 0
    cols = [0] * n  # column of queen in each row

    def is_safe(row, col):
        for prev_row in range(row):
            if (cols[prev_row] == col or
                abs(cols[prev_row] - col) == abs(prev_row - row)):
                return False
        return True

    def backtrack(row):
        nonlocal count
        if row == n:
            count += 1
            return
        for col in range(n):
            if is_safe(row, col):
                cols[row] = col
                backtrack(row + 1)

    backtrack(0)
    return count
